[DataContractAttribute] // Isso avisa o sistema: "Use essa classe para montar a tela"
internal final class JobAtualizaVIPContract
{
    // Variáveis privadas para guardar os valores
    private CustGroupId custGroupId;
    private Amount      creditMax;

}

Method.Source:
    // Método para o Grupo de Clientes
[
    DataMemberAttribute, // Avisa que esse campo deve aparecer na tela
    SysOperationLabelAttribute(literalStr("Grupo de Clientes")), // O nome na tela
    SysOperationHelpTextAttribute(literalStr("Selecione o grupo para atualizar"))
]
public CustGroupId parmCustGroupId(CustGroupId _custGroupId = custGroupId)
{
    custGroupId = _custGroupId;
    return custGroupId;
}

[
    DataMemberAttribute,
    SysOperationLabelAttribute(literalStr("Novo Limite")),
    SysOperationHelpTextAttribute(literalStr("Informe o novo valor máximo de crédito"))
]
public Amount parmCreditMax(Amount _creditMax = creditMax)
{
    creditMax = _creditMax;
    return creditMax;
}
